  5→use App\Jobs\MyJob;
  6→use App\Lib\Facade\CoreApiLib;
  7→use App\Models\MailConfig;
  8→use App\Models\Sfuser;
  9→use App\Service\DailyReportService;
 10→use App\Service\EncryptService;
 11→use Illuminate\Support\Arr;
 12→use Illuminate\Support\Facades\DB;
 13→
 14→class DailyReportAiEmailJob extends MyJob
 15→{
 16→    public $queue = 'default';
 17→
 18→    /** 手动触发时传入具体 task ID，跳过时间/周期匹配（必须 public，private 属性队列序列化后丢失） */
 19→    public ?int $taskId;
 20→
 21→    public function __construct(?int $taskId = null)
 22→    {
 23→        $this->taskId = $taskId;
 24→    }
 25→
 26→    public function handle(): bool
 27→    {
 28→        // 手动触发：直接处理指定任务，不检查时间和周期
 29→        if ($this->taskId) {
 30→            $task = DB::table('daily_report_ai_email_tasks')
 31→                ->whereNull('deleted_at')
 32→                ->where('id', $this->taskId)
 33→                ->first();
 34→
 35→            if (!$task) {
 36→                info("[lbl][0416-AI日报][AiEmailJob] manual trigger: task={$this->taskId} not found");
 37→                return true;
 38→            }
 39→
 40→            info("[lbl][0416-AI日报][AiEmailJob] manual trigger: task={$this->taskId}");
 41→            $this->processTask($task);
 42→            info("[lbl][0416-AI日报][AiEmailJob] manual trigger: task={$this->taskId} done");
 43→            return true;
 44→        }
 45→
 46→        // 定时调度：按时间和周期匹配任务
 47→        $now = now();
 48→        $currentTime = $now->format('H:i');
 49→        $currentDayOfWeek = $now->dayOfWeekIso; // 1=Monday, 7=Sunday
 50→        $currentDayOfMonth = $now->day;
 51→
 52→        info("[lbl][0416-AI日报][AiEmailJob] handle started, currentTime={$currentTime}, dayOfWeek={$currentDayOfWeek}, dayOfMonth={$currentDayOfMonth}");
 53→
 54→        $tasks = DB::table('daily_report_ai_email_tasks')
 55→            ->where('is_on', 1)
 56→            ->whereNull('deleted_at')
 57→            ->where('send_time', $currentTime)
 58→            ->get();
 59→
 60→        if ($tasks->isEmpty()) {
 61→            info("[lbl][0416-AI日报][AiEmailJob] no matching tasks for time={$currentTime}, skip");
 62→            return true;
 63→        }
 64→
 65→        info("[lbl][0416-AI日报][AiEmailJob] found {$tasks->count()} task(s) for time={$currentTime}");
 66→
 67→        foreach ($tasks as $task) {
 68→            if (!$this->shouldSendNow($task, $currentDayOfWeek, $currentDayOfMonth)) {
 69→                continue;
 70→            }
 71→
 72→            try {
 73→                $this->processTask($task);
 74→            } catch (\Throwable $e) {
 75→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} failed: {$e->getMessage()}".$e->getTraceAsString());
 76→            }
 77→        }
 78→
 79→        info('[lbl][0416-AI日报][AiEmailJob] finished');
 80→        return true;
 81→    }
 82→
 83→    private function shouldSendNow(object $task, int $dayOfWeek, int $dayOfMonth): bool
 84→    {
 85→        $sendDay = (int)($task->send_day ?? 1);
 86→
 87→        return match ($task->send_cycle) {
 88→            'daily' => true,
 89→            'weekly' => $dayOfWeek === $sendDay,
 90→            'monthly' => $this->isMonthlyMatch($sendDay, $dayOfMonth),
 91→            default => false,
 92→        };
 93→    }
 94→
 95→    /**
 96→     * 月度匹配：如果设定日超过当月天数，则在当月最后一天触发.
 97→     */
 98→    private function isMonthlyMatch(int $sendDay, int $dayOfMonth): bool
 99→    {
100→        $lastDayOfMonth = (int)now()->endOfMonth()->day;
101→        $effectiveDay = min($sendDay, $lastDayOfMonth);
102→
103→        return $dayOfMonth === $effectiveDay;
104→    }
105→
106→    private function processTask(object $task): void
107→    {
108→        $taskStartTime = microtime(true);
109→        $sfuserId = $task->sfuser_id;
110→
111→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} processTask start", [
112→            'sfuser_id' => $sfuserId,
113→            'dimension' => $task->dimension,
114→            'report_range' => $task->report_range,
115→            'send_cycle' => $task->send_cycle,
116→            'prompt_len' => mb_strlen($task->system_prompt ?? ''),
117→        ]);
118→
119→        // 读取邮箱配置
120→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
121→        if (!$mc || empty(Arr::get($mc->config, 'to_email'))) {
122→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no email config, skip");
123→            return;
124→        }
125→
126→        $toEmails = Arr::get($mc->config, 'to_email');
127→        $sfuserToken = Arr::get($mc->config, 'sfuser_authorized_token', '');
128→        if (!$sfuserToken) {
129→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no sfuser_token, skip");
130→            return;
131→        }
132→
133→        // 确定日报日期范围
134→        [$startDate, $endDate] = $this->getDateRange($task->report_range);
135→
136→        // 拉取该用户能看到日报的全部员工（维度只决定分组方式）
137→        $t0 = microtime(true);
138→        $dailyService = app(DailyReportService::class);
139→        $subordinates = $dailyService->getSubordinates($sfuserId);
140→        // group_users 是二维数组 [groupId => [userId, ...]]，需要 flatten
141→        $groupUserIds = [];
142→        foreach ($subordinates['group_users'] as $userIds) {
143→            $groupUserIds = array_merge($groupUserIds, $userIds);
144→        }
145→        $targetUserIds = array_unique(array_merge(
146→            $subordinates['direct_subordinates'],
147→            $subordinates['depart_subordinates'],
148→            $subordinates['other_subordinates'],
149→            $subordinates['focus_users'],
150→            $groupUserIds
151→        ));
152→
153→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} getSubordinates done", [
154→            'elapsed' => round(microtime(true) - $t0, 2),
155→            'target_user_count' => count($targetUserIds),
156→            'direct' => count($subordinates['direct_subordinates']),
157→            'depart' => count($subordinates['depart_subordinates']),
158→            'other' => count($subordinates['other_subordinates']),
159→            'focus' => count($subordinates['focus_users']),
160→            'group' => count($groupUserIds),
161→        ]);
162→
163→        if (empty($targetUserIds)) {
164→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no visible users, skip");
165→            return;
166→        }
167→
168→        // 拉取日报数据
169→        $t0 = microtime(true);
170→        $data = $dailyService->getOthersDailyReportListEnable(
171→            $startDate,
172→            $endDate,
173→            $sfuserId,
174→            $targetUserIds,
175→            10000
176→        );
177→        $reportCount = count($data['reports']['report_list'] ?? []);
178→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} getReports done", [
179→            'elapsed' => round(microtime(true) - $t0, 2),
180→            'date_range' => "{$startDate}~{$endDate}",
181→            'report_count' => $reportCount,
182→        ]);
183→
184→        if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
185→            info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} no report data, skip");
186→            return;
187→        }
188→
189→        $reportList = $data['reports']['report_list'];
190→
191→        // 收集所有日报涉及的 sfuser_id
192→        $reportSfuserIds = array_unique(array_column($reportList, 'sfuser_id'));
193→
194→        // 查询分组信息：按部门需要 department_id + department_name，按直接主管需要 direct_supervisor_id + direct_supervisor_nickname
195→        $sfuserGroupMap = $this->buildGroupMap($reportSfuserIds, $task->dimension);
196→
197→        // 按维度分组日报
198→        $grouped = [];
199→        foreach ($reportList as $report) {
200→            $uid = $report['sfuser_id'];
201→            $groupKey = $sfuserGroupMap[$uid]['key'] ?? 'unknown';
202→            $grouped[$groupKey]['name'] = $sfuserGroupMap[$uid]['name'] ?? '';
203→            $grouped[$groupKey]['reports'][] = $report;
204→        }
205→
206→        $groupSummary = array_map(fn ($g) => ($g['name'] ?? '?').'('.count($g['reports']).'人)', $grouped);
207→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} grouped", [
208→            'dimension' => $task->dimension,
209→            'group_count' => count($grouped),
210→            'groups' => $groupSummary,
211→            'to_emails' => $toEmails,
212→        ]);
213→
214→        // 每个分组独立发送一封邮件，各自独立 AI 分析
215→        $groupIndex = 0;
216→        $totalGroups = count($grouped);
217→        foreach ($grouped as $groupKey => $group) {
218→            ++$groupIndex;
219→            try {
220→                $groupName = $group['name'];
221→                $reports = $group['reports'];
222→
223→                $dimensionLabel = $task->dimension === 'direct_manager' ? '直属主管' : '部门';
224→                $groupNameMarked = EncryptService::app()->markEncrString($groupName);
225→                // 在日报内容前加上分组上下文，解密后 AI 能识别
226→                $content = "<p><b>{$dimensionLabel}：{$groupNameMarked}</b></p>\n";
227→                $no = 0;
228→                foreach ($reports as $report) {
229→                    $nickname = $report['data']['nickname'] ?? '';
230→                    if (empty($nickname)) {
231→                        continue;
232→                    }
233→                    $nickname = EncryptService::app()->markEncrString(e($nickname));
234→                    $reportContent = EncryptService::app()->markEncrString($report['content']);
235→                    ++$no;
236→                    $content .= '<p><b>'.$no.'、 '.$nickname.'</b></p>';
237→                    $content .= '<div style="border:1px solid #eee;padding:8px;margin-bottom:12px;">'.$reportContent.'</div>';
238→                }
239→
240→                if ($no === 0) {
241→                    info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} group={$groupName} no valid reports, skip");
242→                    continue;
243→                }
244→
245→                $subject = "【{$startDate}】 {$task->name}（{$dimensionLabel}：{$groupNameMarked}）- 智能日报";
246→
247→                $params = [
248→                    'decrypt_config' => [
249→                        'obj' => '$this',
250→                        'decrypt_columns' => [],
251→                        'partly_decrypt_columns' => ['content', 'subject'],
252→                    ],
253→                    'receivers' => [[
254→                        'type' => 'token',
255→                        'tokens' => [$sfuserToken],
256→                        'filter' => 'emails',
257→                        'filter_map' => ['emails' => $toEmails],
258→                    ]],
259→                    'content' => $content,
260→                    'subject' => $subject,
261→                    'ai_analysis_config' => [
262→                        'system_prompt' => $task->system_prompt,
263→                        'compress' => true,
264→                    ],
265→                ];
266→
267→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} [{$groupIndex}/{$totalGroups}] sending", [
268→                    'group_key' => $groupKey,
269→                    'group_name' => $groupName,
270→                    'report_count' => $no,
271→                    'content_bytes' => strlen($content),
272→                    'content_chars' => mb_strlen($content),
273→                    'subject' => $subject,
274→                ]);
275→
276→                $t0 = microtime(true);
277→                $result = CoreApiLib::sendRequest('master-api/mail/send-decr', $params);
278→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} [{$groupIndex}/{$totalGroups}] CoreApi responded", [
279→                    'group_name' => $groupName,
280→                    'elapsed' => round(microtime(true) - $t0, 2),
281→                    'result_code' => $result['error_code'] ?? null,
282→                    'result_msg' => $result['error_msg'] ?? null,
283→                ]);
284→            } catch (\Throwable $e) {
285→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} [{$groupIndex}/{$totalGroups}] group={$group['name']} failed", [
286→                    'error' => $e->getMessage(),
287→                    'trace' => mb_substr($e->getTraceAsString(), 0, 500),
288→                ]);
289→            }
290→
291→            // 分组间隔 2 分钟，避免短时间内多个大请求打满 Vertex AI TPM 配额
292→            if ($groupIndex < $totalGroups) {
293→                info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} sleeping 120s before next group");
294→                sleep(120);
295→            }
296→        }
297→
298→        info("[lbl][0416-AI日报][AiEmailJob] task={$task->id} all groups sent", [
299→            'total_groups' => $totalGroups,
300→            'total_elapsed' => round(microtime(true) - $taskStartTime, 2),
301→        ]);
302→    }
303→
304→    /**
305→     * 根据维度构建 sfuser_id => ['key' => 分组键, 'name' => 分组名] 的映射.
306→     */
307→    private function buildGroupMap(array $sfuserIds, string $dimension): array
308→    {
309→        if (empty($sfuserIds)) {
310→            return [];
311→        }
312→
313→        $map = [];
314→
315→        if ($dimension === 'direct_manager') {
316→            // 按直接主管分组
317→            $users = Sfuser::whereIn('id', $sfuserIds)
318→                ->select('id', 'direct_supervisor_id', 'direct_supervisor_nickname')
319→                ->get();
320→
321→            foreach ($users as $user) {
322→                $managerId = $user->direct_supervisor_id ?: 0;
323→                $managerName = $user->direct_supervisor_nickname ?: '无直接主管';
324→                $map[$user->id] = [
325→                    'key' => "mgr_{$managerId}",
326→                    'name' => $managerName,
327→                ];
328→            }
329→        } else {
330→            // 按部门分组
331→            $users = Sfuser::whereIn('id', $sfuserIds)
332→                ->select('id', 'department_id')
333→                ->get();
334→
335→            // 批量查部门名称
336→            $deptIds = $users->pluck('department_id')->filter()->unique()->values()->toArray();
337→            $deptNames = [];
338→            if (!empty($deptIds)) {
339→                $deptNames = DB::table('job_departments')
340→                    ->whereIn('department_id', $deptIds)
341→                    ->pluck('department_name', 'department_id')
342→                    ->toArray();
343→            }
344→
345→            foreach ($users as $user) {
346→                $deptId = $user->department_id ?: 0;
347→                $deptName = $deptNames[$deptId] ?? '未分配部门';
348→                $map[$user->id] = [
349→                    'key' => "dept_{$deptId}",
350→                    'name' => $deptName,
351→                ];
352→            }
353→        }
354→
355→        return $map;
356→    }
357→
358→    private function getDateRange(string $reportRange): array
359→    {
360→        $today = now()->toDateString();
361→        return match ($reportRange) {
362→            'last_3_days' => [now()->subDays(2)->toDateString(), $today],
363→            'last_7_days' => [now()->subDays(6)->toDateString(), $today],
364→            default => [$today, $today],
365→        };
366→    }
367→}
