123→        \Log::info('[lbl][0416-AI日报][AiEmail][UPDATE] 切换邮件任务开关', ['sfuser_id' => $sfuserId, 'task_id' => $id, 'is_on' => $isOn]);
124→
125→        return $this->responseJsonSuccess();
126→    }
127→
128→    /**
129→     * 手动触发：将指定任务 dispatch 到 ai-email 队列，立即执行一次完整的邮件发送流程.
130→     */
131→    public function taskTrigger(Request $request): JsonResponse
132→    {
133→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
134→        if (!$this->inWhitelist($sfuserId)) {
135→            return $this->responseJsonFail('无权限');
136→        }
137→
138→        $taskId = (int)$request->input('id');
139→        $task = DB::table('daily_report_ai_email_tasks')
140→            ->where('id', $taskId)
141→            ->where('sfuser_id', $sfuserId)
142→            ->whereNull('deleted_at')
143→            ->first();
144→
145→        if (!$task) {
146→            return $this->responseJsonFail('任务不存在');
147→        }
148→
149→        DailyReportAiEmailJob::dispatch($taskId);
150→
151→        \Log::info('[lbl][0416-AI日报][AiEmail][TRIGGER] 手动触发邮件任务', ['sfuser_id' => $sfuserId, 'task_id' => $taskId]);
152→
153→        return $this->responseJsonSuccess();
154→    }
155→
156→    /**
157→     * 测试 Prompt 效果：后端查询加密日报数据，返回 JSON，AI 分析由 oa-core TransferRequestService 完成。
158→     */
159→    public function taskTest(Request $request): JsonResponse
160→    {
161→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
162→        if (!$this->inWhitelist($sfuserId)) {
163→            return $this->responseJsonFail('无权限');
164→        }
165→
166→        $systemPrompt = $request->input('system_prompt', '');
167→        $dimension = $request->input('dimension', 'department');
168→        $reportRange = $request->input('report_range', 'today');
169→        $groupKey = $request->input('group_key', '');
170→
171→        // 计算日期范围
172→        $today = now()->toDateString();
173→        [$startDate, $endDate] = match ($reportRange) {
174→            'last_3_days' => [now()->subDays(2)->toDateString(), $today],
175→            'last_7_days' => [now()->subDays(6)->toDateString(), $today],
176→            default => [$today, $today],
177→        };
178→
179→        // 拉取该用户能看到日报的全部员工
180→        $dailyService = app(DailyReportService::class);
181→        $subordinates = $dailyService->getSubordinates($sfuserId);
182→        $groupUserIds = [];
183→        foreach ($subordinates['group_users'] as $userIds) {
184→            $groupUserIds = array_merge($groupUserIds, $userIds);
185→        }
186→        $targetUserIds = array_unique(array_merge(
187→            $subordinates['direct_subordinates'],
188→            $subordinates['depart_subordinates'],
189→            $subordinates['other_subordinates'],
190→            $subordinates['focus_users'],
191→            $groupUserIds
192→        ));
193→
194→        if (empty($targetUserIds)) {
195→            return $this->responseJsonFail('没有可查看的员工');
196→        }
197→
198→        // 拉取日报数据
199→        $data = $dailyService->getOthersDailyReportListEnable($startDate, $endDate, $sfuserId, $targetUserIds, 10000);
200→        if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
201→            return $this->responseJsonFail('所选日期范围内没有日报数据');
202→        }
203→
204→        $reportList = $data['reports']['report_list'];
205→        $reportSfuserIds = array_unique(array_column($reportList, 'sfuser_id'));
206→
207→        // 构建分组映射
208→        $sfuserGroupMap = $this->buildGroupMap($reportSfuserIds, $dimension);
209→
210→        // 按维度分组日报
211→        $grouped = [];
212→        foreach ($reportList as $report) {
213→            $uid = $report['sfuser_id'];
214→            $key = $sfuserGroupMap[$uid]['key'] ?? 'unknown';
215→            $grouped[$key]['name'] = $sfuserGroupMap[$uid]['name'] ?? '';
216→            $grouped[$key]['reports'][] = $report;
217→        }
218→
219→        // 找到用户选中的分组，找不到则取第一个
220→        $targetGroup = $grouped[$groupKey] ?? reset($grouped);
221→        if (empty($targetGroup) || empty($targetGroup['reports'])) {
222→            return $this->responseJsonFail('所选分组没有日报数据');
223→        }
224→
225→        // 构建带加密标记的内容（oa-core 负责解密）
226→        $groupNameMarked = EncryptService::app()->markEncrString($targetGroup['name']);
227→        $content = "【分组：{$groupNameMarked}】\n\n";
228→        $no = 0;
229→        foreach ($targetGroup['reports'] as $report) {
230→            $nickname = $report['data']['nickname'] ?? '';
231→            if (empty($nickname)) {
232→                continue;
233→            }
234→            $nickname = EncryptService::app()->markEncrString(e($nickname));
235→            $reportContent = EncryptService::app()->markEncrString($report['content']);
236→            ++$no;
237→            $content .= $no.'、 '.$nickname."\n".$reportContent."\n\n";
238→        }
239→
240→        if ($no === 0) {
241→            return $this->responseJsonFail('该分组没有有效的日报内容');
242→        }
243→
244→        \Log::info('[lbl][0416-AI日报][AiEmail][TEST] 开始测试 Prompt', [
245→            'sfuser_id' => $sfuserId,
246→            'dimension' => $dimension,
247→            'group_key' => $groupKey,
248→            'group_name' => $targetGroup['name'],
249→            'report_count' => $no,
250→            'content_len' => mb_strlen($content),
251→        ]);
252→
253→        // 从 MailConfig 读取 sfuser_authorized_token
254→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
255→        $sfuserToken = $mc ? Arr::get($mc->config, 'sfuser_authorized_token', '') : '';
256→        if (empty($sfuserToken)) {
257→            return $this->responseJsonFail('未配置邮件授权 Token，请先在管理后台配置邮件');
258→        }
259→
260→        // 构建摘要
261→        $dimensionLabel = $dimension === 'direct_manager' ? '按直接主管' : '按部门';
262→        $rangeLabel = match ($reportRange) {
263→            'last_3_days' => '近3天',
264→            'last_7_days' => '近7天',
265→            default => '今日',
266→        };
267→        $dateRange = $startDate === $endDate ? $startDate : "{$startDate} ~ {$endDate}";
268→
269→        // 返回数据 + decrypt_config + ai_analysis_config，由 oa-core TransferRequestService 做解密+AI streaming
270→        return $this->responseJsonSuccess([
271→            'content' => $content,
272→            'summary' => "{$dimensionLabel} · {$rangeLabel}（{$dateRange}）· {$no}份日报",
273→            'decrypt_config' => [
274→                'obj' => '$this',
275→                'decrypt_columns' => [],
276→                'partly_decrypt_columns' => ['content'],
277→                'tokens' => [$sfuserToken],
278→                'operation' => 'send_email',
279→            ],
280→            'ai_analysis_config' => [
281→                'system_prompt' => $systemPrompt,
282→                'target_field' => 'content',
283→                'compress' => true,
284→            ],
285→        ]);
286→    }
287→
288→    /**
289→     * 根据维度构建 sfuser_id => ['key' => 分组键, 'name' => 分组名] 的映射.
290→     * 复用 DailyReportAiEmailJob 中的分组逻辑.
291→     */
292→    private function buildGroupMap(array $sfuserIds, string $dimension): array
293→    {
294→        if (empty($sfuserIds)) {
295→            return [];
296→        }
297→
298→        $map = [];
299→
300→        if ($dimension === 'direct_manager') {
301→            $users = Sfuser::whereIn('id', $sfuserIds)
302→                ->select('id', 'direct_supervisor_id', 'direct_supervisor_nickname')
303→                ->get();
304→            foreach ($users as $user) {
305→                $managerId = $user->direct_supervisor_id ?: 0;
306→                $managerName = $user->direct_supervisor_nickname ?: '无直接主管';
307→                $map[$user->id] = [
308→                    'key' => "mgr_{$managerId}",
309→                    'name' => $managerName,
310→                ];
311→            }
312→        } else {
313→            $users = Sfuser::whereIn('id', $sfuserIds)
314→                ->select('id', 'department_id')
315→                ->get();
316→            $deptIds = $users->pluck('department_id')->filter()->unique()->values()->toArray();
317→            $deptNames = [];
318→            if (!empty($deptIds)) {
319→                $deptNames = DB::table('job_departments')
320→                    ->whereIn('department_id', $deptIds)
321→                    ->pluck('department_name', 'department_id')
322→                    ->toArray();
323→            }
324→            foreach ($users as $user) {
325→                $deptId = $user->department_id ?: 0;
326→                $deptName = $deptNames[$deptId] ?? '未分配部门';
327→                $map[$user->id] = [
328→                    'key' => "dept_{$deptId}",
329→                    'name' => $deptName,
330→                ];
331→            }
332→        }
333→
334→        return $map;
335→    }
336→
337→    private function inWhitelist(int $sfuserId): bool
338→    {
339→        return in_array($sfuserId, self::AI_EMAIL_ALLOWED_IDS);
340→    }
