  3→namespace App\Lib;
  4→
  5→use App\Exceptions\ExceptionCode as Code;
  6→use App\Exceptions\RemoteException;
  7→use App\Exceptions\UserException;
  8→use App\Lib\Facade\MyGuzzle;
  9→use GuzzleHttp\Pool;
 10→use GuzzleHttp\Psr7\Request;
 11→use Illuminate\Support\Arr;
 12→use Illuminate\Support\Facades\Validator;
 13→
 14→abstract class ApiLib
 15→{
 16→    public const CONCURRENCY = 5;
 17→
 18→    /** 打印请求结果的长度限制. */
 19→    public const RES_PRINT_LEN = 1024;
 20→
 21→    /** 请求出现错误时打印的长度限制. */
 22→    public const RES_ERR_SHOW_LEN = 128;
 23→
 24→    /** @var int */
 25→    protected $game_id;
 26→
 27→    /** @var string */
 28→    protected $api_url;
 29→
 30→    /** @var string */
 31→    protected $api_key;
 32→
 33→    /** @var string */
 34→    protected $api_secret;
 35→
 36→    /** @var array */
 37→    protected $asyncRequest = [];
 38→
 39→    /**
 40→     * uri请求统一处理.
 41→     *
 42→     * @param string $uri
 43→     * @param array $params
 44→     * @param array $options
 45→     * @param mixed $contentType
 46→     *
 47→     * @return array
 48→     */
 49→    public function sendRequest(
 50→        string $uri,
 51→        array $params,
 52→        array $options = [],
 53→        array $guzzle_options = [],
 54→        bool $check_reponse = true,
 55→        $contentType = 'json',
 56→        array $header = [],
 57→        bool $return_header = false
 58→    ): array {
 59→        if (empty($options['disable_validate'])) {
 60→            $params = $this->validateParams($uri, $params);
 61→        }
 62→
 63→        $params = $this->signature($params);
 64→        $res_json = $this->getResponse($uri, $params, $options, $guzzle_options, $contentType, $header, $return_header);
 65→
 66→        // 下载文件时，请求返回文件流
 67→        if (!empty($options['is_download'])) {
 68→            return [];
 69→        }
 70→
 71→        $response = json_decode($res_json, true);
 72→        if ($check_reponse) {
 73→            $this->checkResponse($response);
 74→        }
 75→
 76→        return $response;
 77→    }
 78→
 79→    /**
 80→     * 执行异步请求request，callback 接受的参数为response(array类型), index(int类型，当前请求在数组中的位置，即第几个请求).
 81→     *
 82→     * @param callable $callback
 83→     * @param array $options
 84→     * @return void
 85→     */
 86→    public function sendRequestAsync(?callable $callback = null, array $options = [])
 87→    {
 88→        $client = MyGuzzle::client($options);
 89→
 90→        $requests = function () {
 91→            foreach ($this->asyncRequest as $request) {
 92→                $requestUrl = $this->api_url.'/'.$request[0];
 93→                yield new Request('POST', $requestUrl, ['Content-Type' => 'application/json'], my_json_encode($request[1]));
 94→            }
 95→        };
 96→
 97→        $pool = new Pool($client, $requests(), [
 98→            'concurrency' => self::CONCURRENCY,
 99→            'fulfilled' => function ($response, $index) use ($callback, $options) {
100→                $res = $response->getBody();
101→                if (!empty($options['is_download'])) {
102→                    return [];
103→                }
104→
105→                $resp = json_decode($res, true);
106→                $this->checkResponse($resp);
107→                if ($callback !== null) {
108→                    return $callback($resp, $index);
109→                }
110→
111→                return [];
112→            },
113→            'rejected' => function ($reason, $index) {
114→                $params = $this->asyncRequest[$index];
115→                throw new RemoteException('index : '.$index.' params : '.my_json_encode($params).' reason : '.$reason);
116→            },
117→        ]);
118→
119→        $pool->promise()->wait();
120→    }
121→
122→    public function addAsyncRequest(string $uri, array $params, array $guzzle_options = []): void
123→    {
124→        if (empty($guzzle_options['disable_validate'])) {
125→            $params = $this->validateParams($uri, $params);
126→        }
127→
128→        $params = $this->signature($params);
129→        $this->asyncRequest[] = [$uri, array_merge($params, $guzzle_options)];
130→    }
131→
132→    /**
133→     * 给请求参数添加time、client_id和签名.
134→     *
135→     * @param array $params
136→     *
137→     * @return array
138→     */
139→    abstract protected function signature(array $params): array;
140→
141→    /**
142→     * 获取请求api的参数规则.
143→     *
144→     * @param string $uri
145→     *
146→     * @return array
147→     */
148→    abstract protected function getValidateRules(string $uri);
149→
150→    protected function getCacheKey(string $uri, array $params): string
151→    {
152→        return 'Cache:'.md5($uri.json_encode($params));
153→    }
154→
155→    /**
156→     * 参数校验并且过滤配置文件未定义的参数.
157→     *
158→     * @param string $uri
159→     * @param array $params
160→     *
161→     * @return array
162→     */
163→    protected function validateParams(string $uri, array $params): array
164→    {
165→        $config_rules = $this->getValidateRules($uri);
166→
167→        if (empty($config_rules)) {
168→            throw new RemoteException(__('my_api.api_not_exist', ['remote' => static::type()]), 801);
169→        }
170→        // 检查传入的参数是否符合要求
171→        $config_params = $config_rules['params'] ?? [];
172→        if (!empty($config_params)) {
173→            $validator = Validator::make($params, $config_params);
174→            if ($validator->fails()) {
175→                $error_msg = __('my_api.api_error_before_request', ['remote' => static::type()]).implode(' ', $validator->errors()->all());
176→                throw new RemoteException($error_msg, 802);
177→            }
178→        }
179→        // 多地区支持，sys_site 参数需要放行，其他参数过滤掉
180→        return Arr::only($params, array_merge_index(array_keys($config_params), ['sys_site']));
181→    }
182→
183→    /**
184→     * 返回请求结果.
185→     *
186→     * @param string $uri
187→     * @param array $params
188→     * @param array $options
189→     *
190→     * @param array $guzzle_options
191→     * @param mixed $contentType
192→     *
193→     * @return string
194→     */
195→    protected function getResponse(
196→        string $uri,
197→        array $params,
198→        array $options = [],
199→        array $guzzle_options = [],
200→        $contentType = 'json',
201→        array $header = [],
202→        bool $return_header = false
203→    ): string {
204→        $request_url = $this->api_url.'/'.$uri;
205→        return $this->execGuzzle($request_url, $params, $options, $guzzle_options, $contentType, $header, $return_header);
206→    }
207→
208→    /**
209→     * 执行Guzzle请求
210→     *
211→     * @codeCoverageIgnored
212→     *
213→     * @param string $url
214→     * @param mixed $data
215→     * @param array $options
216→     * @param array $guzzle_options
217→     * @param string $contentType
218→     * @param array $header
219→     * @param bool $return_header
220→     *
221→     * @throws \GuzzleHttp\Exception\GuzzleException
222→     * @return string
223→     */
224→    protected function execGuzzle(
225→        string $url,
226→        $data = [],
227→        $options = [],
228→        $guzzle_options = [],
229→        $contentType = 'json',
230→        array $header = [],
231→        bool $return_header = false
232→    ): string {
233→        $methodName = 'GET';
234→        $requestData = [];
235→        if (!empty($data)) {
236→            $methodName = 'POST';
237→            $requestData[$contentType] = $data;
238→        }
239→        if (!empty($guzzle_options)) {
240→            $requestData = array_merge($requestData, $guzzle_options);
241→        }
242→
243→        if (!empty($header)) {
244→            $requestData['headers'] = $header;
245→        }
246→        $response = MyGuzzle::client($options)->request($methodName, $url, $requestData);
247→        $res = $response->getBody();
248→        if ($return_header) {
249→            $res = my_json_encode($response->getHeaders())."\r\n\r\n".$res;
250→        }
251→        return $res;
252→    }
253→
254→    /**
255→     * 将请求的url、参数、选项和返回结果写入日志.
256→     *
257→     * @codeCoverageIgnored
258→     *
259→     * @param string $uri
260→     * @param array $params
261→     * @param array $options
262→     * @param string $res
263→     *
264→     * @return void
265→     */
266→    protected function recordResponse(string $uri, array $params, array $options, string $res): void
267→    {
268→        $log_array = [
269→            'url' => $this->api_url.'/'.$uri,
270→            'params' => $params,
271→            'options' => $options,
272→            'res_json' => substr($res, 0, self::RES_PRINT_LEN),
273→        ];
274→        info(static::class.': '.my_json_encode($log_array));
275→    }
276→
277→    /**
278→     * 检查请求结果.
279→     *
280→     * @param array $response
281→     *
282→     * @return void
283→     */
284→    protected function checkResponse(array &$response): void
285→    {
286→        if (!isset($response['error_code']) && isset($response['error'])) {
287→            $error_code = $response['error'];
288→            $error_msg = $response['error_description'];
289→            unset($response['error'], $response['error_description']);
290→
291→            $data = $response;
292→            $response = compact('error_code', 'error_msg', 'data');
293→        }
294→
295→        if (!isset($response['error_code'])) {
296→            throw new RemoteException(__('my_api.api_res_error').substr(json_encode($response), 0, static::RES_ERR_SHOW_LEN), 803);
297→        }
298→
299→        $response['error_code'] = (string)(
300→            is_numeric($response['error_code']) ? $response['error_code'] : Code::ERR_REMOTE
301→        );
302→
303→        if ($response['error_code'] !== '0') {
304→            if ($response['error_code'] == Code::ERR_USER) {
305→                throw new UserException(__('my_api.api_return', ['remote' => static::type()]).$response['error_msg'], $response['error_code']);
306→            }
307→            throw new RemoteException(__('my_api.api_return', ['remote' => static::type()]).$response['error_msg'], $response['error_code']);
308→        }
309→    }
310→
311→    /**
312→     * 获取 ApiLib 的类型（类名的第一个单词）.
313→     *
314→     * @return string
315→     */
316→    protected static function type(): string
317→    {
318→        preg_match('/^[A-Z][a-z]*/', class_basename(static::class), $names);
319→        $name = $names[0] ?? class_basename(static::class);
320→        return $name;
321→    }
322→}
