class DailyReportAiEmailJob extends MyJob
{
    public $queue = 'default';

    /** 手动触发时传入具体 task ID，跳过时间/周期匹配（必须 public，private 属性队列序列化后丢失） */
    public ?int $taskId;

    public function __construct(?int $taskId = null)
    {
        $this->taskId = $taskId;
    }

    public function handle(): bool
    {
        // 手动触发：直接处理指定任务，不检查时间和周期
        if ($this->taskId) {
            $task = DB::table('daily_report_ai_email_tasks')
                ->whereNull('deleted_at')
                ->where('id', $this->taskId)
                ->first();

            if (!$task) {
                info("[lbl][0416-AI日报][AiEmailJob] manual trigger: task={$this->taskId} not found");
                return true;
            }

            info("[lbl][0416-AI日报][AiEmailJob] manual trigger: task={$this->taskId}");
            $this->processTask($task);
            info("[lbl][0416-AI日报][AiEmailJob] manual trigger: task={$this->taskId} done");
            return true;

