 1→<?php
 2→
 3→namespace App\Jobs;
 4→
 5→use App\Jobs\Notification\DailyReportAiEmailJob;
 6→use Illuminate\Console\Command;
 7→use Illuminate\Support\Facades\Cache;
 8→use Illuminate\Support\Facades\DB;
 9→
10→class AdminRetryDailyReportAiEmail extends Command
11→{
12→    protected $signature = 'retry-daily-report-ai-email';
13→
14→    protected $description = '手动重发 AI 日报邮件（遍历所有开启的 task，每个 task 每天最多执行一次）';
15→
16→    public function handle(): int
17→    {
18→        $cacheKey = 'retry_ai_email:'.now()->toDateString();
19→        if (Cache::has($cacheKey)) {
20→            $this->error('今天已经执行过，跳过');
21→            return 1;
22→        }
23→
24→        $tasks = DB::table('daily_report_ai_email_tasks')
25→            ->where('is_on', 1)
26→            ->whereNull('deleted_at')
27→            ->get(['id', 'name']);
28→
29→        if ($tasks->isEmpty()) {
30→            $this->warn('没有开启的任务');
31→            return 0;
32→        }
33→
34→        foreach ($tasks as $task) {
35→            DailyReportAiEmailJob::dispatch($task->id);
36→            $this->info("dispatched task={$task->id} ({$task->name})");
37→        }
38→
39→        Cache::put($cacheKey, true, now()->endOfDay());
40→        $this->info("共 dispatch {$tasks->count()} 个任务");
41→
42→        return 0;
43→    }
44→}
